import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

export default function AdminDashboard() {
  const { API } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats]   = useState(null);
  const [users, setUsers]   = useState([]);
  const [projects, setProjects] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab]       = useState('overview');
  const [msg, setMsg]       = useState('');

  const h = () => ({ headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }, timeout: 15000 });

  const load = async () => {
    setLoading(true);
    try {
      const [sRes, uRes, pRes, anRes] = await Promise.all([
        axios.get(`${API}/admin/stats`, h()),
        axios.get(`${API}/admin/users`, h()),
        axios.get(`${API}/admin/projects`, h()),
        axios.get(`${API}/announcements`, h()),
      ]);
      setStats(sRes.data);
      setUsers(uRes.data);
      setProjects(pRes.data);
      setAnnouncements(anRes.data);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { load(); }, [API]);

  const handleToggleUser = async (id) => {
    try {
      const res = await axios.put(`${API}/admin/users/${id}/toggle`, {}, h());
      setUsers(prev=>prev.map(u=>u._id===id?{...u,isActive:res.data.isActive}:u));
    } catch { alert('Failed'); }
  };

  const handleDeleteUser = async (id) => {
    if (!window.confirm('Delete this user permanently?')) return;
    try {
      await axios.delete(`${API}/admin/users/${id}`, h());
      setUsers(prev=>prev.filter(u=>u._id!==id));
      setMsg('✅ User deleted');
      setTimeout(()=>setMsg(''),2000);
    } catch { alert('Failed'); }
  };

  const roleColor = { student:'#00d4aa', staff:'#6c63ff', admin:'#ff6b9d' };
  const initials  = (name) => name?.split(' ').map(n=>n[0]).join('').toUpperCase().slice(0,2)||'?';

  const statCards = stats ? [
    { label:'Total Users',     value:stats.totalUsers||0,     icon:'👥', color:'#6c63ff' },
    { label:'Students',        value:stats.students||0,       icon:'🎓', color:'#00d4aa' },
    { label:'Faculty',         value:stats.faculty||0,        icon:'👨‍🏫', color:'#ffb347' },
    { label:'Total Projects',  value:stats.totalProjects||0,  icon:'🗂', color:'#ff6b9d' },
    { label:'Open Projects',   value:stats.openProjects||0,   icon:'✅', color:'#4ade80' },
    { label:'Total Requests',  value:stats.totalRequests||0,  icon:'📬', color:'#60a5fa' },
    { label:'Accepted',        value:stats.acceptedRequests||0,icon:'🤝', color:'#a78bfa' },
    { label:'Announcements',   value:announcements.length,    icon:'📢', color:'#fbbf24' },
  ] : [];

  const tabs = [
    { key:'overview',       label:'📊 Overview' },
    { key:'users',          label:`👥 Users (${users.length})` },
    { key:'projects',       label:`🗂 Projects (${projects.length})` },
    { key:'announcements',  label:`📢 Notices (${announcements.length})` },
  ];

  if (loading) return <div style={{padding:'3rem',textAlign:'center',color:'#6c63ff'}}>⏳ Loading admin dashboard...</div>;

  return (
    <div style={{padding:'2rem',maxWidth:1200,margin:'0 auto'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'2rem',flexWrap:'wrap',gap:'1rem'}}>
        <div>
          <h1 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.25rem'}}>🛡 Admin Dashboard</h1>
          <p style={{color:'#9aa3bf',fontSize:'0.875rem'}}>SIST SkillConnect — Manage users, projects and announcements</p>
        </div>
        <div style={{display:'flex',gap:'0.75rem'}}>
          <button onClick={load} style={{padding:'10px 16px',borderRadius:10,border:'1px solid #252d47',background:'transparent',color:'#9aa3bf',cursor:'pointer',fontSize:'0.875rem'}}>🔄 Refresh</button>
          <Link to="/announcements" style={{padding:'10px 18px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,textDecoration:'none',fontSize:'0.875rem'}}>📢 Post Notice</Link>
        </div>
      </div>

      {msg && <div style={{background:'rgba(74,222,128,0.1)',border:'1px solid #4ade8040',borderRadius:10,padding:'12px',marginBottom:'1rem',color:'#4ade80',fontSize:'0.875rem'}}>{msg}</div>}

      {/* Tabs */}
      <div style={{display:'flex',gap:'0.5rem',marginBottom:'2rem',flexWrap:'wrap'}}>
        {tabs.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)} style={{padding:'8px 18px',borderRadius:8,border:`1px solid ${tab===t.key?'#6c63ff':'#252d47'}`,background:tab===t.key?'rgba(108,99,255,0.15)':'transparent',color:tab===t.key?'#6c63ff':'#9aa3bf',fontWeight:600,cursor:'pointer',fontSize:'0.875rem'}}>{t.label}</button>
        ))}
      </div>

      {/* OVERVIEW TAB */}
      {tab==='overview' && (
        <>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(200px,1fr))',gap:'1rem',marginBottom:'2rem'}}>
            {statCards.map((s,i)=>(
              <div key={i} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem'}}>
                <div style={{fontSize:'1.5rem',marginBottom:'0.5rem'}}>{s.icon}</div>
                <div style={{fontSize:'2rem',fontWeight:800,color:s.color}}>{s.value}</div>
                <div style={{color:'#9aa3bf',fontSize:'0.875rem',marginTop:'0.25rem'}}>{s.label}</div>
              </div>
            ))}
          </div>

          {/* Quick actions */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(220px,1fr))',gap:'1rem'}}>
            {[
              { icon:'👥', label:'Manage Users',        desc:'View, activate or deactivate users', action:()=>setTab('users'),        color:'#6c63ff' },
              { icon:'🗂', label:'Manage Projects',     desc:'View all research projects',         action:()=>setTab('projects'),     color:'#00d4aa' },
              { icon:'📢', label:'Post Announcement',   desc:'Send notices to all users',          action:()=>navigate('/announcements'), color:'#ffb347' },
              { icon:'🏆', label:'View Leaderboard',    desc:'See top performing students',        action:()=>navigate('/leaderboard'),color:'#ff6b9d' },
              { icon:'🔍', label:'Search Users',        desc:'Find any student or faculty',        action:()=>navigate('/search'),    color:'#4ade80' },
              { icon:'📊', label:'Student Reports',     desc:'Browse student achievements',        action:()=>navigate('/students'),  color:'#60a5fa' },
            ].map((a,i)=>(
              <div key={i} onClick={a.action} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',cursor:'pointer',transition:'border-color 0.2s'}}
                onMouseEnter={e=>e.currentTarget.style.borderColor=a.color+'50'}
                onMouseLeave={e=>e.currentTarget.style.borderColor='#252d47'}
              >
                <div style={{fontSize:'1.5rem',marginBottom:'0.5rem'}}>{a.icon}</div>
                <div style={{fontWeight:700,color:'#e8eaf0',marginBottom:'0.25rem'}}>{a.label}</div>
                <div style={{color:'#5c6580',fontSize:'0.8rem'}}>{a.desc}</div>
              </div>
            ))}
          </div>
        </>
      )}

      {/* USERS TAB */}
      {tab==='users' && (
        <div>
          <div style={{display:'flex',gap:'1rem',marginBottom:'1rem',flexWrap:'wrap'}}>
            {['All','Students','Faculty','Admin'].map(f=>(
              <span key={f} style={{padding:'4px 12px',borderRadius:99,background:'#161c2e',border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.8rem',cursor:'pointer'}}
                onClick={()=>{}} >{f}</span>
            ))}
          </div>
          <div style={{display:'flex',flexDirection:'column',gap:'0.5rem'}}>
            {users.map(u=>(
              <div key={u._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:12,padding:'1rem',display:'flex',alignItems:'center',gap:'1rem',flexWrap:'wrap'}}>
                <div style={{width:40,height:40,borderRadius:'50%',background:`linear-gradient(135deg,${roleColor[u.role]||'#6c63ff'}80,${roleColor[u.role]||'#6c63ff'})`,display:'flex',alignItems:'center',justifyContent:'center',color:'#fff',fontWeight:700,flexShrink:0}}>{initials(u.name)}</div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:'0.9rem',display:'flex',alignItems:'center',gap:'0.5rem'}}>
                    {u.name}
                    {!u.isActive && <span style={{padding:'1px 7px',borderRadius:99,background:'rgba(255,87,87,0.1)',color:'#ff5757',border:'1px solid #ff575730',fontSize:'0.65rem',fontWeight:600}}>Inactive</span>}
                  </div>
                  <div style={{color:'#9aa3bf',fontSize:'0.75rem'}}>{u.email}</div>
                  <div style={{color:roleColor[u.role],fontSize:'0.75rem',fontWeight:600,textTransform:'capitalize'}}>{u.role} · {u.department}</div>
                </div>
                <div style={{display:'flex',gap:'0.5rem'}}>
                  <button onClick={()=>handleToggleUser(u._id)} style={{padding:'6px 12px',borderRadius:7,background:u.isActive?'rgba(255,87,87,0.1)':'rgba(74,222,128,0.1)',border:`1px solid ${u.isActive?'#ff575740':'#4ade8040'}`,color:u.isActive?'#ff5757':'#4ade80',fontSize:'0.75rem',fontWeight:600,cursor:'pointer'}}>
                    {u.isActive?'Deactivate':'Activate'}
                  </button>
                  {u.role!=='admin' && <button onClick={()=>handleDeleteUser(u._id)} style={{padding:'6px 12px',borderRadius:7,background:'transparent',border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.75rem',cursor:'pointer'}}>Delete</button>}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* PROJECTS TAB */}
      {tab==='projects' && (
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))',gap:'1rem'}}>
          {projects.map(p=>(
            <div key={p._id} onClick={()=>navigate(`/projects/${p._id}`)} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',cursor:'pointer'}}>
              <div style={{display:'flex',justifyContent:'space-between',marginBottom:'0.5rem'}}>
                <span style={{fontWeight:700,fontSize:'0.9rem',color:'#e8eaf0',flex:1,marginRight:'0.5rem'}}>{p.title}</span>
                <span style={{padding:'2px 8px',borderRadius:99,fontSize:'0.7rem',fontWeight:700,background:p.status==='open'?'rgba(0,212,170,0.1)':'rgba(255,87,87,0.1)',color:p.status==='open'?'#00d4aa':'#ff5757',border:`1px solid ${p.status==='open'?'#00d4aa40':'#ff575740'}`,flexShrink:0}}>{p.status}</span>
              </div>
              <div style={{color:'#9aa3bf',fontSize:'0.8rem',marginBottom:'0.5rem'}}>{p.faculty?.name} · {p.faculty?.department}</div>
              <div style={{display:'flex',gap:'1rem'}}>
                <span style={{color:'#ffb347',fontSize:'0.8rem'}}>👥 {p.acceptedStudents?.length||0} accepted</span>
                <span style={{color:'#6c63ff',fontSize:'0.8rem'}}>Max: {p.maxStudents||5}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ANNOUNCEMENTS TAB */}
      {tab==='announcements' && (
        <div>
          <div style={{display:'flex',justifyContent:'flex-end',marginBottom:'1rem'}}>
            <Link to="/announcements" style={{padding:'10px 20px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,textDecoration:'none',fontSize:'0.875rem'}}>+ Post New Announcement</Link>
          </div>
          <div style={{display:'flex',flexDirection:'column',gap:'0.75rem'}}>
            {announcements.length===0 ? (
              <div style={{textAlign:'center',padding:'3rem',color:'#5c6580'}}>No announcements yet</div>
            ) : announcements.map(a=>(
              <div key={a._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:12,padding:'1.25rem'}}>
                <div style={{fontWeight:700,color:'#e8eaf0',marginBottom:'0.25rem'}}>{a.title}</div>
                <div style={{color:'#9aa3bf',fontSize:'0.875rem',marginBottom:'0.5rem'}}>{a.content?.slice(0,120)}...</div>
                <div style={{color:'#5c6580',fontSize:'0.75rem'}}>{new Date(a.createdAt).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
